(()=>{const jobs=window.BOOTERSPACE_JOBS||[];const root=document.querySelector('[data-portal]');if(!root)return;const category=root.dataset.page||"jobs",per=6;const qEl=document.getElementById('q'),locEl=document.getElementById('locationFilter'),catEl=document.getElementById('categoryFilter'),typeEl=document.getElementById('typeFilter'),wrap=document.getElementById('jobsWrap'),pager=document.getElementById('pagination');let page=1;const norm=s=>(s||'').toLowerCase();function baseFilter(j){if(category==='jobs')return true;if(category==='remote-jobs')return j.type==='Remote'||j.category==='remote';if(category==='fresher-jobs')return j.category==='fresher';if(category==='internships')return j.type==='Internship'||j.category==='internship';if(category==='latest-jobs')return j.category==='latest';return true}function filtered(){return jobs.filter(j=>baseFilter(j)).filter(j=>{const q=norm(qEl?.value);const l=norm(locEl?.value);const c=catEl?.value||'';const t=typeEl?.value||'';return(!q||norm(`${j.title} ${j.company}`).includes(q))&&(!l||norm(j.location).includes(l))&&(!c||j.category===c)&&(!t||j.type===t)}).sort((a,b)=>new Date(b.posted)-new Date(a.posted))}function card(j){return `<article class="job"><div><h3>${j.title}</h3><div class="meta"><span>${j.company}</span><span>${j.location}</span><span>${j.salary}</span><span>${j.type}</span><span>Posted: ${j.posted}</span></div><p class="source">Source: ${j.source}</p></div><div><a class="apply" href="${j.apply}" target="_blank" rel="nofollow noopener">Apply now</a></div></article>`}function render(){const list=filtered();const start=(page-1)*per;const view=list.slice(start,start+per);wrap.innerHTML=view.length?view.map(card).join(''):'<div class="panel muted">No jobs match your filters.</div>';const total=Math.max(1,Math.ceil(list.length/per));pager.innerHTML='';for(let i=1;i<=total;i++){const b=document.createElement('button');b.textContent=i;if(i===page)b.className='active';b.onclick=()=>{page=i;render()};pager.appendChild(b)}}[qEl,locEl,catEl,typeEl].forEach(el=>el&&el.addEventListener('input',()=>{page=1;render()}));render();})();
